insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('sport-studies:3-1-1-types-of-major-events:match:c3c65c1d', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Once-in-a-generation opportunity”?", "options": ["The pattern where the same venue stages an event every time it is held", "A description of how rarely a host city gets the chance to stage a ''one-off'' event", "A major event that repeats on a schedule but is hosted in a different city each time", "A major event that repeats on a schedule and returns to the same venue every time"]}'::jsonb, '{"answer": 1, "explain": "“Once-in-a-generation opportunity” means: A description of how rarely a host city gets the chance to stage a ''one-off'' event"}'::jsonb),
('sport-studies:3-1-1-types-of-major-events:match:af2cabb9', 'sport-studies', 'sport-studies:3-1-1-types-of-major-events', '3.1.1 Types of Major Events', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Scheduling pattern”?", "options": ["The pattern where a different city bids to stage an event each time it is held", "A description of how rarely a host city gets the chance to stage a ''one-off'' event", "The pattern where the same venue stages an event every time it is held", "Whether, and how often, a major event returns to the same host location"]}'::jsonb, '{"answer": 3, "explain": "“Scheduling pattern” means: Whether, and how often, a major event returns to the same host location"}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:exam:f68fa3d4', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these best explains why broadcasters pay large amounts of money for the rights to show a major sporting event?", "options": ["Because the event reaches a huge, international audience across many countries", "Because every host country sets a fixed legal minimum price for all broadcasters", "Because the in-venue crowd alone is normally enough to cover the whole cost", "Because major events are always held in exactly the same country every time"], "hint": "Think about what makes the audience for a major event so much bigger than a local match.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — Because the event reaches a huge, international audience across many countries.</strong></p>\n<ul>\n<li>It is the scale and international reach of the audience that makes broadcast access valuable.</li>\n<li>There is no fixed legal minimum price, the in-venue crowd alone is far smaller than the broadcast audience, and major events do not stay in one country.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:mcq:f5914fde', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'mcq', 'mcq', 1, '{"question": "Which feature best shows that a sporting event has reached ''major'' international scale?", "options": ["The event being organised entirely by unpaid local volunteers from the host town", "Every ticket for the event being sold to a local resident only, with none sold abroad", "Competitors and spectators drawn from two or more different countries", "The competition using exactly the same rules as it did in last year''s edition"]}'::jsonb, '{"answer": 2, "explain": "International scale means competitors and audiences crossing borders — ticket buyers being local, volunteer organisation and unchanged rules do not make an event major."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:mcq:b9f1241a', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'mcq', 'mcq', 1, '{"question": "A host venue is full of people watching live, while millions more follow on television across dozens of countries. What are the millions on television called?", "options": ["The remote or broadcast spectators", "The participants competing in the event", "The host nation''s own athletes", "The in-venue crowd, who are physically inside the stadium watching live"]}'::jsonb, '{"answer": 0, "explain": "People watching via TV/online rather than in person are remote (broadcast) spectators — not participants, home athletes, or the physical in-venue crowd."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:mcq:2fe3334d', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'mcq', 'mcq', 1, '{"question": "Why do broadcasters and sponsors pay large amounts of money for access to a major sporting event?", "options": ["Because a global audience across many countries makes that access highly valuable", "Because every major event legally requires at least one paying sponsor to proceed", "Because the host country''s government fixes each sponsor''s price by law", "Because local spectators alone are usually enough to justify the cost"]}'::jsonb, '{"answer": 0, "explain": "It is the huge, international audience that makes broadcast rights and sponsorship valuable — not a legal requirement, a fixed government price, or local attendance alone."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:mcq:021f10c5', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'mcq', 'mcq', 1, '{"question": "A small regional five-a-side tournament features only teams and fans from the same town. Why would this NOT be classed as a major sporting event?", "options": ["Its participants and spectators are local rather than drawn from other countries", "Because five-a-side football can never be considered a serious, competitive sport", "Because it does not charge any of its spectators an entry fee to attend at all", "Because it is organised by a school rather than by a national governing body"]}'::jsonb, '{"answer": 0, "explain": "Scale — international participants and spectators — is what ''major'' requires; the sport itself, entry fees and who organises it are not the deciding factor here."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:mcq:3776ddf7', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'mcq', 'mcq', 1, '{"question": "Which of these best describes the make-up of a live, in-venue crowd at a major sporting event?", "options": ["Usually a mix of local residents and visitors who have travelled from abroad", "Always made up entirely of people from the host country and nowhere else", "Always made up entirely of overseas visitors, with no local residents at all", "Exactly the same in size as the remote television audience"]}'::jsonb, '{"answer": 0, "explain": "In-venue crowds typically blend local residents with international visitors — they are not purely local, purely overseas, nor the same size as the (much bigger) TV audience."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:mcq:512b084a', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'mcq', 'mcq', 1, '{"question": "A student writes: ''A major event matters because lots of people watch it.'' What is missing from this answer?", "options": ["A very detailed description of the exact stadium seating capacity, given in the total number of seats", "A mention of the word ''sport'' occurring anywhere at all in the sentence", "The full official name of the sporting event that is being discussed", "An explanation of why that huge international scale actually matters to the host country"]}'::jsonb, '{"answer": 3, "explain": "Naming the scale isn''t enough — the mark comes from explaining why that scale matters (media value, investment, exposure), which this answer never reaches."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:tf:b48e233e', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'tf', 'tf', 1, '{"question": "A major sporting event usually has competitors from two or more different countries."}'::jsonb, '{"answer": true, "explain": "That international mix of competitors is one of the defining features of a ''major'' event, as opposed to a purely local competition."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:tf:3c276dbd', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'tf', 'tf', 1, '{"question": "The live, in-venue crowd at a major event is always made up entirely of people from the host country."}'::jsonb, '{"answer": false, "explain": "In-venue crowds are usually a mix of local residents and visitors who have travelled from other countries to attend."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:tf:dfff1ca1', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'tf', 'tf', 1, '{"question": "Remote (television/online) spectators are usually far more numerous than the live in-venue crowd."}'::jsonb, '{"answer": true, "explain": "A stadium can only hold so many people, but the broadcast/online audience reaches many more people across many countries."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:tf:67d3c115', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'tf', 'tf', 1, '{"question": "The international scale of a major event is irrelevant to how much money broadcasters and sponsors are willing to pay."}'::jsonb, '{"answer": false, "explain": "It is the opposite — the size and international reach of the audience is exactly why broadcast rights and sponsorship are so valuable."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:tf:fda8fc9c', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'tf', 'tf', 1, '{"question": "A small tournament with only local teams and local fans could still be classed as a ''major'' sporting event."}'::jsonb, '{"answer": false, "explain": "Without competitors and spectators from other countries, an event stays local/regional rather than reaching ''major'' international scale."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:tf:2a0e454d', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'tf', 'tf', 1, '{"question": "Simply stating that ''a lot of people watch'' a major event is enough to explain why its scale matters."}'::jsonb, '{"answer": false, "explain": "Naming the scale only gets you started — the mark is for explaining why that scale matters, e.g. its effect on media value and investment."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:learn:a74c3ad6', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'learn', 'mcq', 1, '{"readingTitle": "Why a major event''s participants are international", "reading": "<h4>The idea</h4>\n<ul>\n<li>A <strong>major sporting event</strong> (an Olympic Games, a World Cup, a continental championship) is not a domestic fixture. It is <strong>international</strong> — competitors normally travel in from <strong>two or more different countries</strong> to take part under one shared set of rules, in one host location.</li>\n<li>This is one of the features that separates a \"major event\" from a routine local or regional competition, where every competitor usually comes from the same area.</li>\n</ul>\n<h4>What this means for the host</h4>\n<ul>\n<li>Because competitors arrive from abroad, a host city or country has to plan for things a purely local competition never needs: visas and travel for overseas teams, translation, and accommodation for squads from many nations at once.</li>\n<li>The mix of nations competing is part of the spectacle itself — it is a large part of why people want to watch.</li>\n</ul>", "question": "What makes the participants at a major sporting event different from those at a small local competition?", "options": ["They usually travel in from two or more different countries to compete", "They must all be full-time professional athletes earning a large salary", "They are always selected using exactly the same method in every single country", "They only ever compete in events lasting a single afternoon"]}'::jsonb, '{"answer": 0, "explain": "A major event draws competitors from multiple nations, not just professional status, identical selection rules, or event length — none of those make an event ''major''."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:learn:c7942d50', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'learn', 'mcq', 1, '{"readingTitle": "Two kinds of international spectator", "reading": "<h4>Live, in-venue spectators</h4>\n<ul>\n<li>The crowd physically inside the stadium or venue is usually a mix of <strong>local residents</strong> and <strong>visitors who have travelled from other countries</strong> specifically to attend.</li>\n<li>These crowds are large — major events fill the biggest venues a host country has, often for many sessions in a row.</li>\n</ul>\n<h4>Remote spectators — the global audience</h4>\n<ul>\n<li>Far more people watch a major event on <strong>television or online</strong> than could ever fit in a venue. This remote audience is spread across <strong>many countries at once</strong>, often watching in different languages and time zones.</li>\n<li>This global broadcast audience is usually the biggest reason a major event reaches so many more people than any domestic fixture.</li>\n</ul>\n<h4>Putting the two together</h4>\n<ul>\n<li>A major event therefore has an international mix on both sides: <strong>participants</strong> from many nations, and <strong>spectators</strong> split between an international live crowd and a far larger international broadcast audience.</li>\n</ul>", "question": "Which statement correctly separates the two kinds of spectator at a major sporting event?", "options": ["Live spectators are inside the venue; remote spectators watch worldwide via TV or online", "Live spectators only ever exist for indoor events, while remote spectators only exist for outdoor ones", "Remote spectators are always fewer in number than the people inside the venue", "There is no real difference between a live spectator and a remote spectator"]}'::jsonb, '{"answer": 0, "explain": "Live spectators attend in person; remote spectators are the much larger worldwide TV/online audience. The other options invert or deny that split."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:learn:28ff118d', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'learn', 'mcq', 1, '{"readingTitle": "Why the international scale matters", "reading": "<h4>It is part of what makes an event \"major\"</h4>\n<ul>\n<li>An event only really counts as <strong>major</strong> once its competitors and its audience stretch across national borders. Scale is a defining feature, not a side effect — a competition with one nation''s athletes and only local spectators stays a domestic event, however well it is run.</li>\n</ul>\n<h4>It drives the impact on the host</h4>\n<ul>\n<li>The international scale is <strong>why</strong> a major event attracts heavy media coverage, sponsorship and investment — broadcasters and sponsors are paying for access to a huge, worldwide audience, not a local one.</li>\n<li>It is also why hosting brings the host country international exposure: the whole point of a global audience is that people <em>outside</em> the host country are watching it.</li>\n</ul>\n<h4>Exam skill: link scale to reason</h4>\n<ul>\n<li>A weak answer just states the scale (\"lots of people watch\"). A strong answer explains <strong>why the scale matters</strong> — for example, that a global TV audience is what makes broadcast rights and sponsorship so valuable to a host.</li>\n</ul>", "question": "Why does the international scale of participants and spectators matter to a host country?", "options": ["It is a large part of what makes an event ''major'' and drives its media and investment value", "It has no real effect at all on how much investment or media coverage an event ever receives", "It only ever matters for events that are held in winter rather than in the summer months", "It matters solely because it makes ticket prices slightly cheaper for local residents"]}'::jsonb, '{"answer": 0, "explain": "The international scale is what defines ''major'' and is why broadcasters, sponsors and investors are interested — it isn''t irrelevant, seasonal, or about ticket price."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:misc:67eb6804', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Any event with a big crowd inside the stadium counts as a ''major'' international sporting event.</p><p><strong>✅ The correct idea:</strong> A big local crowd is not the same as international scale. What defines a major event is competitors AND spectators being drawn from two or more different countries — including the much larger remote (TV/online) audience across the world, not just how full one venue looks on the day.</p>", "question": "What actually shows that a sporting event has reached ''major'' international scale?", "options": ["Competitors and spectators being drawn from two or more countries, including the global broadcast audience", "The stadium simply being full to its absolute maximum seating capacity on every single day of the entire event", "The event lasting for more than one single day from start to finish in total", "The home nation''s team winning the majority of its matches at the event"]}'::jsonb, '{"answer": 0, "explain": "A full stadium, a long event, or the home team winning does not define ''major'' — the cross-border reach of competitors and viewers does."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:misc:c2f3de52', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''Spectators'' at a major event just means the people sitting in the stadium.</p><p><strong>✅ The correct idea:</strong> That only covers HALF the spectators. The specification splits spectators into live, in-venue spectators AND the much bigger remote audience watching on television or online across many countries. Forgetting the remote audience under-states the true scale of a major event.</p>", "question": "Which group of spectators is often forgotten when students describe a major event''s audience?", "options": ["The remote television or online audience, following the event across many different countries", "The athletes who are actually competing directly in the event itself, out on the field of play", "The officials who referee and run the competition throughout the whole event", "The volunteers who help to run the venue on the day of the event"]}'::jsonb, '{"answer": 0, "explain": "Students often only picture the in-venue crowd and forget the far larger remote broadcast audience — both make up ''spectators''."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:misc:0e7b44ed', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Explaining why international scale ''matters'' just means repeating that lots of people are involved.</p><p><strong>✅ The correct idea:</strong> Restating the scale earns little on its own. The exam rewards a REASON: the scale matters because it is what makes broadcast rights, sponsorship and investment so valuable, and because it is what gives the host country genuine international exposure — not just the raw number of people.</p>", "question": "What is most likely to earn marks when a question asks why international scale ''matters'' to a host?", "options": ["A reason linking the scale to its effect, such as its media value or investment", "Simply repeating, in different words, that a very large number of people are involved", "Listing as many different countries as you can possibly remember off by heart", "A description of what the host country''s national flag actually looks like"]}'::jsonb, '{"answer": 0, "explain": "''Why it matters'' questions need a linked reason (media value, sponsorship, exposure) — restating the number or listing countries does not explain anything."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:tips:cec58acf', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words on this topic — what each one wants", "reading": "<p>Questions on participants and spectators are usually short recall or one step of application. Match your answer length to the command word and the marks:</p>\n<ul>\n<li><strong>Identify / State [1 mark each]</strong> — name a feature. \"State one way a major event''s spectators are international\" = one short point, nothing more.</li>\n<li><strong>Describe [2 marks]</strong> — add a feature or detail. Two linked points, or one point plus a detail.</li>\n<li><strong>Explain [2–4 marks]</strong> — give a reason, using the word <em>because</em>. Say WHY the international scale matters, not just that it exists.</li>\n</ul>\n<p><strong>Read the mark tariff</strong>: a [1] wants one point; a [4] in Section B wants points applied to the scenario you are given, not a general list.</p>", "question": "A question says: ''State one feature that shows a major event''s participants are international [1]''. What is the safest answer?", "options": ["One short, clear point", "A long paragraph covering several ideas", "A list of every country you can name", "A description of your favourite sport"]}'::jsonb, '{"answer": 0, "explain": "''State'' plus [1] mark wants a single clear point — a long paragraph, a list of countries or an unrelated description all waste time for no extra credit."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:tips:c709c5ed', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: name the scale AND why it matters", "reading": "<p>The most common way to lose marks here is stopping at description. Build longer answers as <strong>feature → why it matters</strong>:</p>\n<ul>\n<li><strong>❌ weak:</strong> \"The event has spectators from lots of countries.\"</li>\n<li><strong>✅ strong:</strong> \"The event has a global television audience across many countries, which is why broadcasters and sponsors pay so much for access to it.\"</li>\n</ul>\n<p>In <strong>Section B</strong> you will usually be given a scenario with numbers (countries represented, crowd size, broadcast reach). Use those exact figures in your answer instead of a general example.</p>", "question": "In a Section B scenario question with numbers for crowd size and countries represented, your answer should...", "options": ["use those specific figures from the scenario", "ignore the figures given and describe a different event entirely", "only describe the host country''s own fans", "avoid mentioning numbers of any kind"]}'::jsonb, '{"answer": 0, "explain": "Section B rewards application — using the scenario''s own figures shows you can apply the idea, rather than writing a generic answer."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:tips:865b3266', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> short recall in <strong>Section A</strong> (identify/state a feature of international participants or spectators); applied points in <strong>Section B</strong> scenarios with real numbers; and it can feed a <strong>Section C</strong> 8-mark discussion of why hosting a major event matters to a country.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Always split spectators into two groups: live, in-venue AND remote/broadcast — examiners often want both.</li>\n<li>Never just restate the scale (\"lots of people watch\") — pair it with a reason it matters.</li>\n<li>In Section B, quote the scenario''s own numbers (countries, crowd size) rather than a generic example.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way the participants/spectators here are international is… because…\"</li>\n<li>\"This matters because a bigger, international audience means…\"</li>\n<li>\"However, this scale also brings…\"</li>\n</ul>", "question": "Why is it useful to split ''spectators'' into live and remote in a longer answer?", "options": ["It shows you understand both parts of the true international audience, not just half of it", "It fills space in a longer written answer without adding any real understanding of the topic at all", "It proves that the host venue itself was too small for the event to take place", "It replaces the need to explain why the scale actually matters at all"]}'::jsonb, '{"answer": 0, "explain": "Naming both live and remote spectators shows a fuller, more accurate picture of the audience — but you still need to explain why the scale matters."}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:fib:f7b4d78c', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'fib', 'fib', 1, '{"question": "A major sporting event usually has competitors travelling in from two or more different _____.", "blankOptions": {"B1": ["live", "major", "countries", "remote"]}}'::jsonb, '{"blanks": {"B1": "countries"}}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:fib:f574bf2d', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'fib', 'fib', 1, '{"question": "People watching a major event live inside the stadium are called _____ spectators.", "blankOptions": {"B1": ["remote", "live", "major", "countries"]}}'::jsonb, '{"blanks": {"B1": "live"}}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:fib:0438e01d', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'fib', 'fib', 1, '{"question": "People following a major event on television or online, often from many countries at once, are called _____ spectators.", "blankOptions": {"B1": ["valuable", "countries", "remote", "major"]}}'::jsonb, '{"blanks": {"B1": "remote"}}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:fib:58fa26f9', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'fib', 'fib', 1, '{"question": "The huge, worldwide television audience is what makes broadcast rights and sponsorship so _____ to a host.", "blankOptions": {"B1": ["live", "remote", "major", "valuable"]}}'::jsonb, '{"blanks": {"B1": "valuable"}}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:fib:8963611e', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'fib', 'fib', 1, '{"question": "International scale is part of what makes an event count as _____, rather than a purely local competition.", "blankOptions": {"B1": ["major", "countries", "live", "remote"]}}'::jsonb, '{"blanks": {"B1": "major"}}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:match:58afe25b', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Major sporting event”?", "options": ["The much larger television or online audience, spread across many countries at once", "The combined worldwide viewership that makes broadcast rights and sponsorship valuable", "A competition whose participants and spectators are drawn from two or more countries", "The crowd physically inside the venue, usually a mix of local and overseas visitors"]}'::jsonb, '{"answer": 2, "explain": "“Major sporting event” means: A competition whose participants and spectators are drawn from two or more countries"}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:match:99225ca3', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Participants”?", "options": ["The cross-border reach of competitors and viewers that is part of what makes an event ''major''", "A competition whose participants and spectators are drawn from two or more countries", "The much larger television or online audience, spread across many countries at once", "The competitors taking part, typically travelling in from multiple different nations"]}'::jsonb, '{"answer": 3, "explain": "“Participants” means: The competitors taking part, typically travelling in from multiple different nations"}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:match:ec285c3b', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Live spectators”?", "options": ["The crowd physically inside the venue, usually a mix of local and overseas visitors", "The much larger television or online audience, spread across many countries at once", "The cross-border reach of competitors and viewers that is part of what makes an event ''major''", "The combined worldwide viewership that makes broadcast rights and sponsorship valuable"]}'::jsonb, '{"answer": 0, "explain": "“Live spectators” means: The crowd physically inside the venue, usually a mix of local and overseas visitors"}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:match:b5a5f9df', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Remote spectators”?", "options": ["The combined worldwide viewership that makes broadcast rights and sponsorship valuable", "The much larger television or online audience, spread across many countries at once", "The competitors taking part, typically travelling in from multiple different nations", "The crowd physically inside the venue, usually a mix of local and overseas visitors"]}'::jsonb, '{"answer": 1, "explain": "“Remote spectators” means: The much larger television or online audience, spread across many countries at once"}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:match:10d9f8ae', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Global audience”?", "options": ["The crowd physically inside the venue, usually a mix of local and overseas visitors", "The combined worldwide viewership that makes broadcast rights and sponsorship valuable", "The competitors taking part, typically travelling in from multiple different nations", "The cross-border reach of competitors and viewers that is part of what makes an event ''major''"]}'::jsonb, '{"answer": 1, "explain": "“Global audience” means: The combined worldwide viewership that makes broadcast rights and sponsorship valuable"}'::jsonb),
('sport-studies:3-1-2-participants-and-spectators:match:c249504e', 'sport-studies', 'sport-studies:3-1-2-participants-and-spectators', '3.1.2 Participants and Spectators', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “International scale”?", "options": ["The competitors taking part, typically travelling in from multiple different nations", "The cross-border reach of competitors and viewers that is part of what makes an event ''major''", "The crowd physically inside the venue, usually a mix of local and overseas visitors", "A competition whose participants and spectators are drawn from two or more countries"]}'::jsonb, '{"answer": 1, "explain": "“International scale” means: The cross-border reach of competitors and viewers that is part of what makes an event ''major''"}'::jsonb),
('sport-studies:3-2-pre-event-aspects:exam:d0698c36', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these is most likely to be a reason local residents object to their city bidding for a major sporting event?", "options": ["The bid money could be better spent on other local needs such as schools or hospitals", "Major sporting events are completely banned by law in every single country that could host them", "Bidding always guarantees the event will be successfully hosted in the end", "Construction work never affects any homes near the proposed venues"], "hint": "Think about what residents usually argue the money could be used for instead.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — the bid money could be better spent on other local needs.</strong></p>\n<ul>\n<li>This is the most common real objection: priorities, not opposition to sport itself.</li>\n<li>The other options describe things that are not true of bidding or its effects.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:3-2-pre-event-aspects:mcq:1cb59892', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'mcq', 'mcq', 1, '{"question": "What is a ''bid'' for a major sporting event best described as?", "options": ["A costly, competitive process in which places apply to be chosen as host", "A free vote among fans deciding which city they would most like to visit next", "A short local meeting held only after a winning host has already been confirmed", "A guaranteed contract signed automatically as soon as a stadium design is drawn up"]}'::jsonb, '{"answer": 0, "explain": "Bidding is a costly, competitive process — several places apply and only one is chosen, so it is neither free, automatic, nor something that happens after the decision."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:mcq:3f536482', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'mcq', 'mcq', 1, '{"question": "Which of these is a genuine risk of the infrastructure built before a major sporting event?", "options": ["Ticket sales from the event always cover the entire cost of every stadium and transport link built", "Building to a fixed deadline can run over budget and disrupt local residents for years beforehand", "Local roads are never affected by construction work carried out for a major sporting event", "New venues are only ever built well away from where any local residents actually live"]}'::jsonb, '{"answer": 1, "explain": "Construction to a hard deadline commonly overruns its budget and disrupts local life well before the event — the other options describe outcomes that do not reliably happen."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:mcq:dd8abef3', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'mcq', 'mcq', 1, '{"question": "Why might commercial investment attracted by a bid be seen as only a limited benefit?", "options": ["Sponsors and investors never provide any funding towards a major sporting event", "Sponsor interest is usually tied to the event and can fade once it has finished", "Commercial investment always replaces every penny of public spending completely", "Investors are legally required to fund the event for at least twenty years afterwards"]}'::jsonb, '{"answer": 1, "explain": "Investment is often tied closely to the event itself, so interest and funding can fall away once it ends — that is the limit on this benefit, not that investment never happens."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:mcq:b037e5f0', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'mcq', 'mcq', 1, '{"question": "A city''s bid for a major event fails after months of costly preparation. What does this best show?", "options": ["Bidding guarantees the city a financial return no matter what the final outcome is", "Bidding is a genuine risk, since the cost of preparing it is spent whether it succeeds or fails", "A bid can only ever be submitted once by the same city in its entire history", "Every failed bid is fully refunded in cash by the sport''s international governing body without any exception"]}'::jsonb, '{"answer": 1, "explain": "The money spent preparing a bid is spent regardless of the result, which is exactly why bidding is described as a genuine financial risk, not a safe investment."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:mcq:e221594a', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'mcq', 'mcq', 1, '{"question": "Which reason is most likely to be given by local residents objecting to a bid?", "options": ["The bid money could be better spent on other local needs such as schools or hospitals", "Residents object because major sporting events are against the law in every country", "Residents object because bidding always guarantees the event will be hosted successfully", "Residents object because construction work never affects any nearby homes at all"]}'::jsonb, '{"answer": 0, "explain": "A common objection is that the large sums spent chasing a bid could instead fund more certain local needs — the other options describe things that are not true or not the reason given."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:mcq:a044e2d4', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'mcq', 'mcq', 1, '{"question": "Which sentence best shows the exam skill of weighing pre-event aspects, rather than just listing them?", "options": ["Hosting a major event simply involves bidding, infrastructure and investment all happening", "Bidding can attract investment, but that gain only follows if the costly bid succeeds", "Major sporting events happen in many different countries around the world today", "Infrastructure, investment and employment are all things that genuinely exist"]}'::jsonb, '{"answer": 1, "explain": "Weighing the SAME aspect''s benefit against its risk (bidding can attract investment, but only if it succeeds) shows real understanding — the other options merely list topics."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:tf:9c833212', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'tf', 'tf', 1, '{"question": "Bidding to host a major sporting event is a free and simple process."}'::jsonb, '{"answer": false, "explain": "Bidding is costly and competitive — bid teams spend large sums on presentations, guarantees and planning before any decision is made."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:tf:e566f510', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'tf', 'tf', 1, '{"question": "New stadiums, roads and transport links built before an event can go on to benefit local residents for years afterwards."}'::jsonb, '{"answer": true, "explain": "Infrastructure delivered to the event''s deadline can keep serving residents long after the event has finished — a genuine lasting positive."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:tf:8527a86c', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'tf', 'tf', 1, '{"question": "Every city or country that submits a bid is guaranteed to be chosen as host."}'::jsonb, '{"answer": false, "explain": "Bidding is competitive — usually only one place wins, so every other bidder has spent heavily on a bid that did not succeed."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:tf:77bbb052', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'tf', 'tf', 1, '{"question": "Jobs created constructing venues before an event usually last only until the building work finishes."}'::jsonb, '{"answer": true, "explain": "Most pre-event construction employment is temporary, tied to the build itself, and tends to disappear once the venues are finished."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:tf:73cfc029', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'tf', 'tf', 1, '{"question": "Local and national objections to a bid are only ever about damage to the environment."}'::jsonb, '{"answer": false, "explain": "Objections mainly focus on whether bid money could be better spent on other social needs, and on the disruption of construction — not only the environment."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:tf:6ec25070', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'tf', 'tf', 1, '{"question": "Commercial investment from sponsors can help pay for facilities that public money alone might not cover."}'::jsonb, '{"answer": true, "explain": "Sponsors and investors are drawn to an event''s global attention, and their money can fund facilities beyond what public spending alone could stretch to."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:learn:87043b1b', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'learn', 'mcq', 1, '{"readingTitle": "Bidding for a major event — a costly gamble", "reading": "<h4>What a ''bid'' actually is</h4>\n<ul>\n<li>Before any major event can happen, cities or countries have to <strong>bid</strong> for the right to host it — a formal, competitive process in which each applicant puts forward a detailed proposal to the sport''s governing body.</li>\n<li>Bidding is <strong>expensive in itself</strong>. Putting a bid together — presentations, site visits, financial guarantees, planning documents — costs large sums of money, and that money is spent <em>before</em> anyone knows whether the bid will succeed.</li>\n<li>Because several places usually compete for the same event, most bids <strong>fail</strong>. The losing places still have to pay for the process; only one place gets the event at the end of it.</li>\n</ul>\n<h4>Justifications FOR bidding</h4>\n<ul>\n<li>A strong bid can raise a place''s <strong>international profile</strong> long before the event starts.</li>\n<li>Chasing a bid can unlock political and public support for <strong>investment</strong> that might never have been approved otherwise.</li>\n<li>Working towards a shared bid can build a sense of <strong>national pride</strong> and common purpose.</li>\n</ul>\n<h4>Justifications AGAINST bidding</h4>\n<ul>\n<li>The bidding process costs real money with <strong>no guarantee of success</strong> — if the bid fails, that spending produces nothing.</li>\n<li>Critics argue that money spent chasing a bid could instead go on more certain local needs, such as schools, hospitals or grassroots sport.</li>\n<li>The exam skill here is to <strong>weigh the two sides of the same aspect</strong>: bidding can attract benefits, but it is also a genuine financial risk — never present only one side.</li>\n</ul>", "question": "Which of these best describes why bidding for a major sporting event is risky for the applicant?", "options": ["The process itself is costly and competitive, so a failed bid still leaves a large, unrecovered bill", "The process is free of charge for every applicant, so nobody ever loses out even if their bid ultimately fails", "Only one place is ever allowed to submit a bid for any single major event", "A bid is approved automatically as soon as it is formally submitted for review"]}'::jsonb, '{"answer": 0, "explain": "Bidding costs real money on presentations, guarantees and planning before a winner is known — if the bid fails, that spending is lost, which is the genuine risk."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:learn:75245560', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'learn', 'mcq', 1, '{"readingTitle": "Infrastructure and transport development", "reading": "<h4>The positive side</h4>\n<ul>\n<li>Hosting a major event usually forces new or upgraded <strong>stadiums and venues</strong>, plus improved <strong>roads, rail lines and transport links</strong>, to be finished by a fixed deadline.</li>\n<li>These improvements can <strong>outlive the event</strong> — residents can keep using an upgraded rail line or a new sports venue for years after the closing ceremony.</li>\n</ul>\n<h4>The negative side of the SAME building programme</h4>\n<ul>\n<li>This construction is very costly, and projects built to a hard deadline commonly run <strong>over budget</strong>.</li>\n<li>Venues rushed to meet the event date may not actually suit <strong>local needs</strong> once the event has finished.</li>\n<li>The building work itself causes <strong>years of disruption</strong> beforehand — dug-up roads, noise and congestion for local residents.</li>\n</ul>\n<p>Notice this is <strong>one</strong> aspect (infrastructure) with a genuine upside and a genuine downside — the exam rewards students who can hold both in mind at once, not just list the positive.</p>", "question": "What is a genuine risk attached to infrastructure built before a major sporting event?", "options": ["Every improved transport link instantly becomes free to use for local residents forever", "New stadiums are always demolished the day after they are finished being built", "Rushed building work can run over budget and cause years of local disruption beforehand", "Transport development is banned everywhere a major sporting event takes place"]}'::jsonb, '{"answer": 2, "explain": "Building to a fixed deadline commonly overruns its budget and disrupts local life for years beforehand — a genuine cost that sits alongside the lasting benefit."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:learn:a22e36bb', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'learn', 'mcq', 1, '{"readingTitle": "Financial investment and the jobs it creates", "reading": "<h4>The positive side</h4>\n<ul>\n<li>Major events attract <strong>commercial investment</strong> — sponsors and investors are willing to put money behind an event that draws global attention, funding facilities that public money alone might never stretch to.</li>\n<li>Preparing for the event creates <strong>employment</strong>: construction jobs building venues and transport links, plus further jobs preparing and staffing the event as it approaches.</li>\n</ul>\n<h4>The negative side of the SAME investment and jobs</h4>\n<ul>\n<li>Much of this employment is <strong>temporary</strong> — construction jobs largely disappear once the building work finishes, often well before the event even begins.</li>\n<li>Sponsor interest is usually tied to the event itself, so it can fade quickly once the event is over, meaning any employment boost may not last.</li>\n<li>Relying on private investment can mean handing real decisions — such as naming rights or ticket allocation — over to the sponsors and investors who paid for them.</li>\n</ul>", "question": "Why is the employment created before a major sporting event often described as a limited benefit?", "options": ["No construction jobs are ever created in the years before a major sporting event", "Every job created before the event is guaranteed to last for the entire remainder of that worker''s whole career", "Employment always increases at exactly the same rate that commercial investment falls", "Most of these jobs are tied to construction and preparation, and usually end once that work is finished"]}'::jsonb, '{"answer": 3, "explain": "Construction and preparation jobs are largely temporary — they tend to disappear once the building work is complete, often before the event has even started."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:learn:3f5e3b6a', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'learn', 'mcq', 1, '{"readingTitle": "Objections to bidding — weighing positives against negatives", "reading": "<h4>Why people object to a bid</h4>\n<ul>\n<li>Local residents and national pressure groups often object to a bid <strong>before it is even submitted</strong>, arguing that the huge sums involved would do more good spent on other social needs — schools, hospitals or local sport facilities — than on chasing a bid that might fail.</li>\n<li>Objections can also focus on the years of <strong>disruption</strong> construction brings, or on doubts that the promised jobs and infrastructure will really benefit local people once contractors move on.</li>\n</ul>\n<h4>The exam skill: don''t just list, WEIGH</h4>\n<ul>\n<li><strong>Weak answer:</strong> \"Bidding costs money.\" This names a fact but shows no real understanding.</li>\n<li><strong>Strong answer:</strong> \"Bidding is expensive and competitive, so a city risks spending heavily on a bid that fails; but if it succeeds, the investment attracted can fund lasting infrastructure — the real question is whether that gamble is worth taking.\"</li>\n<li>Every pre-event aspect (bidding, infrastructure, investment, employment) has a positive AND a negative side, and top answers compare <strong>the same aspect''s two sides</strong> rather than one positive from one aspect against one negative from a different aspect.</li>\n</ul>", "question": "A question asks you to discuss objections to bidding for a major event. What shows the strongest understanding?", "options": ["Naming a single positive of hosting the event, with absolutely no further comment added", "Weighing a genuine benefit of bidding against a genuine risk of the same bid", "Listing as many unrelated sports facts as you can possibly recall from memory", "Stating that objections to bidding never happen anywhere in real life"]}'::jsonb, '{"answer": 1, "explain": "Discuss questions reward comparing the benefit and the risk of the SAME aspect (bidding) — naming one fact alone, or listing unrelated facts, does not show that skill."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:misc:acf064c0', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Bidding for a major event is basically free advertising, so there''s no real cost involved.</p><p><strong>✅ The correct idea:</strong> The bidding process itself costs large sums of money — presentations, site visits, guarantees and planning documents all have to be paid for, whether or not the bid succeeds. If the bid fails, that spending is simply lost. Bidding is a genuine financial gamble, not free publicity.</p>", "question": "What is the truth about the cost of bidding for a major sporting event?", "options": ["Bidding costs nothing at all for any of the places that choose to apply for it", "Only the winning bid ever has to pay for the cost of preparing its own bid", "The process itself is costly, whether or not the bid goes on to succeed", "Bids are always fully refunded by the governing body if they are unsuccessful"]}'::jsonb, '{"answer": 2, "explain": "The cost of preparing a bid is spent regardless of the outcome, which is exactly why a failed bid is a real financial loss for the applicant."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:misc:f06fb53d', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> New infrastructure built before an event is only ever a good thing for local people.</p><p><strong>✅ The correct idea:</strong> Infrastructure has a genuine positive AND a genuine negative side. Yes, new venues and transport links can serve residents for years — but rushed builds may not fit local needs afterwards, projects can run over budget, and the construction itself disrupts local life for years beforehand. A strong answer holds both sides in mind.</p>", "question": "Which statement best captures the full picture of pre-event infrastructure?", "options": ["It can bring lasting benefits, but also cost overruns and years of disruption", "It only ever benefits local residents, with no downside of any kind at all", "It never affects local residents in any way at all, whether positive or negative", "It is always finished many years before the event actually needs it to be ready"]}'::jsonb, '{"answer": 0, "explain": "Infrastructure carries a real upside (lasting facilities) and a real downside (overruns, disruption) — a one-sided answer misses half the picture."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:misc:92fd500c', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The jobs created before a major event are permanent, long-term jobs for local people.</p><p><strong>✅ The correct idea:</strong> Most pre-event jobs are tied to construction and preparation, and they tend to disappear once the building work is finished — often well before the event itself even starts. Treating this employment boost as permanent overstates the benefit.</p>", "question": "What is true about most jobs created in the run-up to a major sporting event?", "options": ["They are guaranteed to continue for the rest of the worker''s entire career", "No jobs of any kind are ever created before a major sporting event takes place", "They only ever begin on the very same day that the event itself starts", "They are largely temporary, tied to construction and preparation work"]}'::jsonb, '{"answer": 3, "explain": "Construction and preparation jobs are mostly temporary and tend to end once the building phase is complete, which limits how lasting this benefit really is."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:misc:130957a5', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Objecting to a bid means you don''t want your country to host any sport at all.</p><p><strong>✅ The correct idea:</strong> Objections are usually about priorities, not about opposing sport itself. Residents and pressure groups typically question whether the money spent chasing a bid is better used on other local or national needs, such as schools, hospitals or grassroots sport — not that sport shouldn''t happen.</p>", "question": "What do most objections to a bidding process actually argue?", "options": ["That sport itself should not be allowed to take place anywhere at all", "That the money involved could be better spent on other social needs", "That every major sporting event should be cancelled immediately as a result", "That bidding always succeeds, no matter which city or country applies"]}'::jsonb, '{"answer": 1, "explain": "Objections are usually about spending priorities — whether the money could do more good elsewhere — rather than opposition to sport itself."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:tips:5c1b4f50', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for pre-event questions — what each one wants", "reading": "<p>Pre-event questions range from quick recall to full evaluation. Match your answer length to the command word and the mark tariff:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two pre-event aspects [2]\" = two names, one mark each, nothing more.</li>\n<li><strong>Describe</strong> — say what it involves. \"Describe the bidding process\" = give its features (competitive, costly, run by the governing body).</li>\n<li><strong>Explain</strong> — give a reason. \"Explain why bidding is risky\" = a point <em>plus</em> why (because the cost is spent whether or not it succeeds).</li>\n<li><strong>Discuss</strong> — weigh both sides. This is where pre-event questions are usually won or lost — see the next tip.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [4] in Section B wants points applied to the scenario; [8] wants a balanced discussion with a judgement.</p>", "question": "A question says: ''Identify two pre-event aspects of hosting a major event [2]''. What is the safest answer?", "options": ["A long paragraph that only explores one single aspect in real detail", "Two named aspects, such as bidding and infrastructure", "A list of every single aspect that you can possibly remember", "One aspect explained in full, with a supporting reason given"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Exploring one aspect in depth, or listing far more than asked, wastes time without extra reward."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:tips:2060adf0', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: weigh the positive against the negative of the SAME aspect", "reading": "<p>The single most common way to lose marks on this topic is treating positives and negatives as separate lists. Build every longer answer as <strong>aspect → benefit → but → risk</strong>:</p>\n<ul>\n<li><strong>❌ weak:</strong> \"Bidding is good because it brings investment. Infrastructure is bad because it costs money.\" (two different aspects, no real comparison)</li>\n<li><strong>✅ strong:</strong> \"Bidding can attract investment that funds lasting infrastructure, but that gain only follows if the costly bid actually succeeds.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario. Use a detail <em>from that scenario</em> when you weigh the aspect, rather than a general example.</p>", "question": "Which of these best follows the ''aspect → benefit → but → risk'' structure?", "options": ["Bidding is competitive, and infrastructure is expensive to build", "Infrastructure and employment are both things that simply exist before an event", "Objections happen, and investment also happens, in some countries", "Bidding can raise a city''s profile, but the cost is lost if the bid fails"]}'::jsonb, '{"answer": 3, "explain": "This links ONE aspect''s benefit to ITS OWN risk (profile gained, but cost lost if it fails) — the other options just list separate facts side by side."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:tips:db69b096', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where pre-event aspects appear + sentence starters", "reading": "<p><strong>Where it shows up:</strong> pre-event aspects appear as quick recall in <strong>Section A</strong> (identify/state), as applied points in <strong>Section B</strong> scenarios about a specific bidding city, and as balanced <strong>Section C</strong> 8-mark discussions weighing up whether hosting is worth it.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the five aspects (bidding, infrastructure/transport, investment, employment, objections) so you always have material to draw on.</li>\n<li>For every aspect, memorise <em>one</em> benefit and <em>one</em> risk — that pairing is usually where the marks sit.</li>\n<li>Watch for temporary vs lasting effects: infrastructure often lasts, jobs and sponsor interest usually don''t — a sharp evaluation point.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One benefit of bidding for this event is… because…\"</li>\n<li>\"However, this comes with a risk, because…\"</li>\n<li>\"Overall, whether this is worth it depends on…\"</li>\n</ul>", "question": "Why is noticing ''temporary vs lasting'' effects a useful evaluation point?", "options": ["It shows some benefits fade quickly while others can last for years", "It fills space without adding any real understanding to the answer given here at all", "It proves that pre-event aspects never have any real effect on anyone", "It means a Section C answer can skip giving any kind of final judgement"]}'::jsonb, '{"answer": 0, "explain": "Spotting that jobs and sponsor interest are often temporary, while infrastructure can last, shows the kind of balanced thinking that lifts a Section C answer."}'::jsonb),
('sport-studies:3-2-pre-event-aspects:fib:d49b2003', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'fib', 'fib', 1, '{"question": "Bidding to host a major event is a _____ process, meaning several places apply for the same event.", "blankOptions": {"B1": ["temporary", "infrastructure", "commercial", "competitive"]}}'::jsonb, '{"blanks": {"B1": "competitive"}}'::jsonb),
('sport-studies:3-2-pre-event-aspects:fib:c0fd275f', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'fib', 'fib', 1, '{"question": "Because a bid can fail, the money spent preparing it is often described as a financial _____.", "blankOptions": {"B1": ["temporary", "infrastructure", "risk", "competitive"]}}'::jsonb, '{"blanks": {"B1": "risk"}}'::jsonb),
('sport-studies:3-2-pre-event-aspects:fib:0044333b', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'fib', 'fib', 1, '{"question": "New stadiums, roads and transport links built before an event are examples of _____ development.", "blankOptions": {"B1": ["risk", "infrastructure", "commercial", "temporary"]}}'::jsonb, '{"blanks": {"B1": "infrastructure"}}'::jsonb),
('sport-studies:3-2-pre-event-aspects:fib:0d2ba587', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'fib', 'fib', 1, '{"question": "Sponsors and investors provide _____ investment that can fund facilities public money alone might not cover.", "blankOptions": {"B1": ["competitive", "commercial", "infrastructure", "needs"]}}'::jsonb, '{"blanks": {"B1": "commercial"}}'::jsonb),
('sport-studies:3-2-pre-event-aspects:fib:0296c873', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'fib', 'fib', 1, '{"question": "Construction work before a major event usually creates _____ employment that ends once the building finishes.", "blankOptions": {"B1": ["needs", "commercial", "risk", "temporary"]}}'::jsonb, '{"blanks": {"B1": "temporary"}}'::jsonb),
('sport-studies:3-2-pre-event-aspects:fib:e50d66c0', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'fib', 'fib', 1, '{"question": "Objectors often argue that bid money could be better spent on other local or national _____.", "blankOptions": {"B1": ["risk", "needs", "commercial", "competitive"]}}'::jsonb, '{"blanks": {"B1": "needs"}}'::jsonb),
('sport-studies:3-2-pre-event-aspects:match:fc319989', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Bidding”?", "options": ["Jobs created constructing venues and preparing a place before a major event takes place", "Opposition at a country-wide level questioning why public money should fund a bid", "The costly, competitive process of formally applying to be chosen as host of a major event", "Money that sponsors and investors put into an event, hoping for exposure or a return"]}'::jsonb, '{"answer": 2, "explain": "“Bidding” means: The costly, competitive process of formally applying to be chosen as host of a major event"}'::jsonb),
('sport-studies:3-2-pre-event-aspects:match:198f6d36', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Infrastructure development”?", "options": ["Money that sponsors and investors put into an event, hoping for exposure or a return", "Opposition at a country-wide level questioning why public money should fund a bid", "Jobs created constructing venues and preparing a place before a major event takes place", "Building or upgrading stadiums and venues so a place is ready to host a major event"]}'::jsonb, '{"answer": 3, "explain": "“Infrastructure development” means: Building or upgrading stadiums and venues so a place is ready to host a major event"}'::jsonb),
('sport-studies:3-2-pre-event-aspects:match:7312f621', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Transport development”?", "options": ["Improving roads, rail and other links so visitors and residents can reach a major event", "Money that sponsors and investors put into an event, hoping for exposure or a return", "Building or upgrading stadiums and venues so a place is ready to host a major event", "The costly, competitive process of formally applying to be chosen as host of a major event"]}'::jsonb, '{"answer": 0, "explain": "“Transport development” means: Improving roads, rail and other links so visitors and residents can reach a major event"}'::jsonb),
('sport-studies:3-2-pre-event-aspects:match:5d44f99b', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Commercial investment”?", "options": ["Opposition from residents who feel bid money could be better spent on other local needs", "The costly, competitive process of formally applying to be chosen as host of a major event", "Improving roads, rail and other links so visitors and residents can reach a major event", "Money that sponsors and investors put into an event, hoping for exposure or a return"]}'::jsonb, '{"answer": 3, "explain": "“Commercial investment” means: Money that sponsors and investors put into an event, hoping for exposure or a return"}'::jsonb),
('sport-studies:3-2-pre-event-aspects:match:fc873785', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Pre-event employment”?", "options": ["Jobs created constructing venues and preparing a place before a major event takes place", "Money that sponsors and investors put into an event, hoping for exposure or a return", "Opposition at a country-wide level questioning why public money should fund a bid", "The costly, competitive process of formally applying to be chosen as host of a major event"]}'::jsonb, '{"answer": 0, "explain": "“Pre-event employment” means: Jobs created constructing venues and preparing a place before a major event takes place"}'::jsonb),
('sport-studies:3-2-pre-event-aspects:match:6988ce22', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Local objection”?", "options": ["The costly, competitive process of formally applying to be chosen as host of a major event", "Building or upgrading stadiums and venues so a place is ready to host a major event", "Jobs created constructing venues and preparing a place before a major event takes place", "Opposition from residents who feel bid money could be better spent on other local needs"]}'::jsonb, '{"answer": 3, "explain": "“Local objection” means: Opposition from residents who feel bid money could be better spent on other local needs"}'::jsonb),
('sport-studies:3-2-pre-event-aspects:match:445a7b79', 'sport-studies', 'sport-studies:3-2-pre-event-aspects', '3.2 Pre-Event Aspects', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “National objection”?", "options": ["Building or upgrading stadiums and venues so a place is ready to host a major event", "Money that sponsors and investors put into an event, hoping for exposure or a return", "Opposition from residents who feel bid money could be better spent on other local needs", "Opposition at a country-wide level questioning why public money should fund a bid"]}'::jsonb, '{"answer": 3, "explain": "“National objection” means: Opposition at a country-wide level questioning why public money should fund a bid"}'::jsonb),
('sport-studies:3-3-1-during-the-event:exam:3c8b33bd', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these is most likely to be a NEGATIVE effect while a major sporting event is being staged?", "options": ["Increased litter, noise and transport pressure around the busy host venues", "A rise in national interest in the sport(s) being played across the whole country", "An increase in short-term jobs created just to cover the period the event is running", "A rise in direct tourism spending on tickets and hotels close to the venues"], "hint": "Three of these are named during-event positives. Only one is a genuine negative.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — Increased litter, noise and transport pressure around the busy host venues.</strong></p>\n<ul>\n<li>This is a genuine during-event negative — the strain large crowds put on the host area.</li>\n<li>Interest, jobs and tourism are all named during-event positives, not negatives.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:3-3-1-during-the-event:mcq:d9fe896a', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'mcq', 'mcq', 1, '{"question": "Which of these is an example of ''improved social infrastructure in use'' during a major event?", "options": ["Trains and roads that were built for the event are now busy carrying spectators and staff", "A national team is knocked out in the opening round in front of a disappointed home crowd", "Newspapers and broadcasters give the sport far more coverage than it usually receives", "Temporary stewarding and security jobs are created just to cover the event period, then end"]}'::jsonb, '{"answer": 0, "explain": "Using new or upgraded transport and venues that were built beforehand is social infrastructure in use. The other options describe results, media coverage and employment instead."}'::jsonb),
('sport-studies:3-3-1-during-the-event:mcq:74a13bc7', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'mcq', 'mcq', 1, '{"question": "Which of these is most likely to be a NEGATIVE effect while a major event is being staged?", "options": ["Increased litter, noise and transport pressure building up around the busy host venues", "A rise in national interest in the sport(s) being played across the whole country", "An increase in short-term jobs, such as stewarding and security, created just to cover the event period", "A rise in direct tourism spending on tickets and hotels close to the venues"]}'::jsonb, '{"answer": 0, "explain": "Extra litter, noise and transport pressure on the host area is a during-event negative. The other three are all named positives of the during-event stage."}'::jsonb),
('sport-studies:3-3-1-during-the-event:mcq:05644090', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'mcq', 'mcq', 1, '{"question": "A host nation''s team performs badly and is knocked out early. What is the most likely effect of this?", "options": ["It can damage the national pride and morale that hosting the event was meant to build", "It always causes a permanent, nationwide collapse in interest in every sport forever", "It automatically leads to every local business near the venues closing down immediately", "It has no effect at all on how people in the host country feel about the event"]}'::jsonb, '{"answer": 0, "explain": "Poor performance by the host nation can hurt national pride and morale — it does not wipe out all sport forever, close businesses, or leave feelings unaffected."}'::jsonb),
('sport-studies:3-3-1-during-the-event:mcq:fd8db43c', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'mcq', 'mcq', 1, '{"question": "What is meant by ''indirect tourism'' during a major event?", "options": ["Spending nearby that is not part of the event itself, such as meals, shops and sightseeing", "Money spent directly on match tickets and hotel rooms right next to the venue itself", "The wages paid to permanent, full-time staff who already worked at the venue long beforehand", "The cost of building a brand new stadium in the years before the event even opens"]}'::jsonb, '{"answer": 0, "explain": "Indirect tourism is extra spending near the event that is not the event itself, like meals and sightseeing. Ticket/hotel spend is direct tourism; wages and construction are different effects."}'::jsonb),
('sport-studies:3-3-1-during-the-event:mcq:a2122f59', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'mcq', 'mcq', 1, '{"question": "Why might regional areas away from the host venues feel neglected during a major event?", "options": ["Investment, media attention and spending can focus heavily on the host area, leaving them out", "Every part of the country always receives an exactly identical share of investment and coverage", "Regional areas are legally required to close all of their sports facilities during the event", "National governing bodies are banned from operating anywhere outside the host city itself"]}'::jsonb, '{"answer": 0, "explain": "Attention and investment concentrate on the host area, so non-host regions can feel left out and under-invested — the other options are not real effects of hosting."}'::jsonb),
('sport-studies:3-3-1-during-the-event:mcq:05c36abd', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'mcq', 'mcq', 1, '{"question": "A stadium suffers ticketing chaos and this is widely reported by journalists during the event. This is best described as...", "options": ["negative media coverage of an organisational or facility problem", "an increase in short-term employment created for the event period", "a rise in direct tourism spending on tickets close to the venue", "improved national status because the event is receiving so much coverage"]}'::jsonb, '{"answer": 0, "explain": "Reporting on an organisational failure like ticketing chaos is negative media coverage — it is not employment, tourism spend, or a status boost."}'::jsonb),
('sport-studies:3-3-1-during-the-event:tf:cd43e050', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'tf', 'tf', 1, '{"question": "Using new venues and transport links that were built for the event is a during-event positive."}'::jsonb, '{"answer": true, "explain": "This is ''improved social infrastructure in use'' — a genuine positive that only exists once the built infrastructure is actually being used."}'::jsonb),
('sport-studies:3-3-1-during-the-event:tf:9aef1c43', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'tf', 'tf', 1, '{"question": "Regional areas away from the host venues almost always benefit just as much as the host area itself."}'::jsonb, '{"answer": false, "explain": "Attention and investment concentrate on the host area, so other regions can feel neglected and under-invested instead of benefiting equally."}'::jsonb),
('sport-studies:3-3-1-during-the-event:tf:e8e01570', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'tf', 'tf', 1, '{"question": "An increase in short-term jobs, such as stewarding and security, is a during-event positive."}'::jsonb, '{"answer": true, "explain": "Temporary roles created just to cover the event period are a genuine short-term employment positive of the during-event stage."}'::jsonb),
('sport-studies:3-3-1-during-the-event:tf:26a643a1', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'tf', 'tf', 1, '{"question": "Negative media coverage during a major event is always about which team wins or loses."}'::jsonb, '{"answer": false, "explain": "Negative coverage is often about organisational or facility problems, like ticketing chaos or transport failures, not just results."}'::jsonb),
('sport-studies:3-3-1-during-the-event:tf:dade928d', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'tf', 'tf', 1, '{"question": "Gathering huge crowds in one place for a major event can raise the risk of crime."}'::jsonb, '{"answer": true, "explain": "Large crowds and high-profile international attention can increase the potential for terrorism and crime while the event is on."}'::jsonb),
('sport-studies:3-3-1-during-the-event:tf:eec7d223', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'tf', 'tf', 1, '{"question": "A poor performance by the host nation''s team has no effect on national morale."}'::jsonb, '{"answer": false, "explain": "The opposite is true — poor home performance can directly damage the national pride and morale that hosting was meant to build."}'::jsonb),
('sport-studies:3-3-1-during-the-event:learn:a42449ae', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'learn', 'mcq', 1, '{"readingTitle": "During the event — the middle stage of hosting", "reading": "<h4>Three stages, one event</h4>\n<ul>\n<li>Hosting a major event is usually looked at in three stages: <strong>before</strong> the event (bidding, building, investing), <strong>during</strong> the event (this page), and <strong>after</strong> the event (the long-term legacy).</li>\n<li>The during-event stage covers everything that happens <strong>while the event is actually running</strong> — from the opening moment to the final result, whatever the sport.</li>\n</ul>\n<h4>Why the exam keeps the stages separate</h4>\n<ul>\n<li>Some effects only exist <strong>while the crowds, athletes and media are physically there</strong> — a full stadium, live rolling coverage, a short-term spike in visitor numbers. These fade away once the event finishes.</li>\n<li>You must keep the stages straight in an answer: an effect that happens <strong>during</strong> the event (like a burst of national interest) is not the same as one that happens <strong>before</strong> it (like a construction job) or <strong>after</strong> it (like an empty stadium sitting unused).</li>\n<li>Just like the other two stages, during-event effects can be <strong>positive or negative</strong> at the very same time, for the very same event.</li>\n</ul>", "question": "Which of these best describes the ''during the event'' stage that this page covers?", "options": ["Everything that happens while the event is actually running, from start to finish", "The years spent bidding for the right to host the event before it is even confirmed", "What happens to the venues once the whole event has completely finished and closed", "The construction of new stadiums and transport links that takes place before the event opens"]}'::jsonb, '{"answer": 0, "explain": "During-the-event effects only exist while the event is running. Bidding and building happen before it; what happens to venues afterwards is the post-event/legacy stage."}'::jsonb),
('sport-studies:3-3-1-during-the-event:learn:9784ad18', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'learn', 'mcq', 1, '{"readingTitle": "The positives while the event is on", "reading": "<h4>Community and pride</h4>\n<ul>\n<li><strong>Improved national morale and social cohesion</strong> — a shared, feel-good sense of pride can bring people from across the country together while the event is running.</li>\n<li><strong>Increased national status</strong> — hosting successfully can raise how the country is seen and respected by other nations while it is in the international spotlight.</li>\n<li><strong>Greater national interest in the sport(s)</strong> — people who do not normally follow the sport(s) often start watching and talking about them while the event is on home soil.</li>\n</ul>\n<h4>Facilities, tourism and jobs</h4>\n<ul>\n<li><strong>Improved social infrastructure in use</strong> — venues, transport links and facilities that were built or upgraded beforehand are now genuinely being used, by visitors and local residents alike.</li>\n<li><strong>A rise in direct tourism</strong> — spending tied straight to the event itself, such as match tickets and hotel stays close to a venue.</li>\n<li><strong>A rise in indirect tourism</strong> — extra spending nearby that is not part of the event itself, such as restaurants, shops and sightseeing that visitors pay for while they are in the area.</li>\n<li><strong>An increase in short-term employment</strong> — temporary jobs (stewarding, security, hospitality, transport) created just to cover the event period.</li>\n</ul>\n<h4>Media</h4>\n<ul>\n<li><strong>Increased media coverage of the sport(s)</strong> — a rise in the amount of national and international press, TV and online coverage the sport(s) receive, well above their usual level.</li>\n</ul>", "question": "A shared feeling of pride that brings people across the country together while a major event is on is best described as...", "options": ["increased national morale and social cohesion", "an increase in short-term employment created just for the event period", "a rise in indirect tourism spending near the venues while visitors are in town", "extra litter, noise and transport pressure around the host venues, which local residents notice straight away"]}'::jsonb, '{"answer": 0, "explain": "That shared feel-good sense of pride and unity is national morale/social cohesion — the other options describe jobs, tourism spending and a negative effect, not this one."}'::jsonb),
('sport-studies:3-3-1-during-the-event:learn:e9afc1f4', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'learn', 'mcq', 1, '{"readingTitle": "The negatives while the event is on", "reading": "<h4>Everyday strain on the host area</h4>\n<ul>\n<li><strong>Increased transport, litter and noise</strong> — large crowds moving through a host area put real pressure on roads, public transport, rubbish collection and general noise levels.</li>\n</ul>\n<h4>Safety and security</h4>\n<ul>\n<li><strong>Potential for increased terrorism and crime</strong> — a major event gathers huge crowds and international attention in one place, which can raise the security risk for the time it is running.</li>\n</ul>\n<h4>Performance and fairness</h4>\n<ul>\n<li><strong>Poor performance by the home nation or team</strong> — if the host team does badly, it can damage the very national pride and morale that hosting was supposed to build.</li>\n<li><strong>Regional areas not involved can feel neglected</strong> — parts of the country away from the actual venues may feel under-invested and left out, while attention and spending are focused on the host area only.</li>\n</ul>\n<h4>Media</h4>\n<ul>\n<li><strong>Negative media coverage of organisational or facility problems</strong> — issues such as ticketing chaos, transport failures or an unfinished venue getting reported instead of the sport itself.</li>\n</ul>", "question": "What does ''regional areas feeling neglected'' mean as a during-event negative?", "options": ["Parts of the country away from the host venues feeling left out while investment and attention focus on the host area", "The host nation''s team losing every single one of its matches at every different venue right through the whole event and every round", "A rise in litter and noise directly around the main stadium during the opening ceremony", "Extra security staff being hired only for the week the event is taking place"]}'::jsonb, '{"answer": 0, "explain": "Regional neglect is about non-host areas feeling overlooked and under-invested — not about results, litter, or extra security staffing."}'::jsonb),
('sport-studies:3-3-1-during-the-event:learn:366fec73', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'learn', 'mcq', 1, '{"readingTitle": "Weighing positives against negatives — the exam skill", "reading": "<h4>Naming effects is only the start</h4>\n<ul>\n<li>Weak answer: <em>\"A positive is national pride. A negative is crime.\"</em> That names two effects but shows no real understanding.</li>\n<li>Strong answer: <em>\"National morale can rise if the home team does well in front of a home crowd, but if the venue suffers ticketing problems, the negative media coverage of that failure can cancel out the goodwill just as quickly.\"</em></li>\n<li>Higher-mark questions want you to <strong>weigh</strong> positives against negatives — which one matters more, in this specific situation, and why — before reaching a judgement.</li>\n</ul>\n<h4>Using a scenario properly</h4>\n<ul>\n<li>Section B and C questions usually give you a made-up event or host area. Pick out a detail from <em>that</em> scenario — a named area, a named problem — rather than writing a general answer that ignores it.</li>\n<li>A good during-event answer often shows that the <strong>same event</strong> can be producing a positive and a negative <strong>at the same time</strong>, for different groups of people.</li>\n</ul>", "question": "In a scenario question about a named host city, the strongest answers usually...", "options": ["use a detail from the scenario and weigh it against another effect before reaching a judgement", "name as many user groups and pieces of technology as can possibly be remembered from earlier topics", "describe only the positives, because negatives are not worth mentioning", "copy the exact wording printed in the question back into the answer"]}'::jsonb, '{"answer": 0, "explain": "The best answers apply a detail from the scenario, set a positive against a negative, and reach a judgement — not a one-sided list or a repeat of the question."}'::jsonb),
('sport-studies:3-3-1-during-the-event:misc:22c055d8', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The ''during the event'' stage is basically the same as the pre-event stage, since it''s all just part of ''hosting''.</p><p><strong>✅ The correct idea:</strong> The exam treats them as separate stages with separate effects. Pre-event (3.2) covers bidding, building and investing BEFORE the event opens. During-event (this page) only covers effects that exist WHILE the event is actually running — a busy stadium, live coverage, a short-term tourism spike. Mixing the two loses marks because you have named the wrong stage''s effect.</p>", "question": "A question specifically asks about the ''during the event'' stage. Which answer fits?", "options": ["A short-term rise in visitor spending while the event is actually taking place", "The years spent putting together the bid to host the event in the first place", "Construction jobs created while building a brand new stadium before the event opens", "Money spent maintaining an empty stadium for years after the whole event has ended"]}'::jsonb, '{"answer": 0, "explain": "Only the visitor-spending answer happens while the event is running. The others describe the pre-event bidding/building stage or the post-event legacy stage."}'::jsonb),
('sport-studies:3-3-1-during-the-event:misc:c5001e80', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A good answer on this topic only needs to list positives, because that''s what hosting is ''supposed'' to bring.</p><p><strong>✅ The correct idea:</strong> Higher-mark questions want a BALANCED answer — genuine negatives (transport strain, crime risk, regional neglect, negative coverage) sit alongside the positives, often for the very same event. A one-sided list of only positives is capped in the higher bands, even if every point named is accurate.</p>", "question": "Why does a one-sided list of only positives lose marks on a higher-tariff question?", "options": ["Because higher bands reward a balanced discussion, weighing positives against negatives", "Because positives are never actually true at any single point during a major sporting event", "Because examiners only ever accept negative points on this specific topic", "Because listing more than three positives is against the exam''s rules"]}'::jsonb, '{"answer": 0, "explain": "Level-of-response marking rewards weighing both sides and reaching a judgement — a one-sided list, however accurate, cannot reach the top band."}'::jsonb),
('sport-studies:3-3-1-during-the-event:misc:a9fa7df6', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''National status'' and ''national morale'' mean exactly the same thing, so you can use either word for either idea.</p><p><strong>✅ The correct idea:</strong> They are related but different. National STATUS is about how the country is seen and respected by OTHER nations while it hosts. National MORALE/cohesion is about how people INSIDE the country feel — their own shared pride and unity. A strong answer keeps the two separate rather than treating them as interchangeable.</p>", "question": "Which of these describes ''national status'' rather than ''national morale''?", "options": ["How the host country is seen and respected by other nations during the event", "A shared feel-good sense of pride felt by people within the host country itself", "The temporary jobs created to help run the event while it is taking place", "The rubbish, noise and transport pressure that builds up around a busy venue"]}'::jsonb, '{"answer": 0, "explain": "National status is about the country''s external reputation abroad. Internal shared pride is morale/cohesion; the other two options are unrelated effects."}'::jsonb),
('sport-studies:3-3-1-during-the-event:misc:a5abd6de', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Negative media coverage during a major event must mean the athletes played badly.</p><p><strong>✅ The correct idea:</strong> It is usually about organisational or facility problems instead — things like ticketing chaos, transport failures, or an unfinished venue. A country can host superb sport and still receive negative coverage because of how the event itself was run, not how anyone actually performed.</p>", "question": "Negative media coverage during a major event most often reports on...", "options": ["organisational or facility problems, such as ticketing chaos or transport failures", "the exact final score of every single fixture played right through the whole event", "the weather forecast for the week the event is scheduled to take place", "the total number of tickets sold before the event had even opened"]}'::jsonb, '{"answer": 0, "explain": "It is problems with how the event is organised or run — not scores, weather, or advance ticket sales — that usually generate negative coverage."}'::jsonb),
('sport-studies:3-3-1-during-the-event:tips:b6a042cb', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Questions on this topic range from quick recall to a full extended response. Match your answer to the command word and the mark tariff:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one negative during-event effect [1]\" = one named effect, nothing more.</li>\n<li><strong>Describe</strong> — add a feature or detail. \"Describe a during-event positive\" = say what it involves, not just its name.</li>\n<li><strong>Explain</strong> — give a reason, usually using the word <em>because</em>. \"Explain why regional areas may feel neglected\" wants the effect PLUS why it happens.</li>\n<li><strong>Discuss / Evaluate</strong> — the 6/8-mark levelled question. Weigh positives against negatives, apply the scenario, and end with a judgement.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1]–[2] wants named points; a 4-mark Section B question wants points applied to a scenario; an 8-mark Section C question wants balance and a judgement.</p>", "question": "A question says: ''State one positive effect during a major event [1]''. What is the safest answer?", "options": ["One named positive effect", "A full paragraph weighing several positives and negatives", "Two negative effects instead of a positive", "A description of the event''s opening ceremony"]}'::jsonb, '{"answer": 0, "explain": "''State'' + [1] = one named point. Writing a full discussion, giving negatives instead, or describing a ceremony all miss what a 1-mark ''state'' question wants."}'::jsonb),
('sport-studies:3-3-1-during-the-event:tips:a3edd6ae', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: weigh it up, don''t just list it", "reading": "<p>The most common way to lose marks on Discuss/Evaluate questions here is writing a one-sided list. Build a higher-mark answer as <strong>positive → negative → judgement</strong>:</p>\n<ul>\n<li><strong>❌ low band:</strong> \"A positive is national pride. Another positive is tourism. Another positive is jobs.\"</li>\n<li><strong>✅ higher band:</strong> \"National pride can rise if the home team performs well, HOWEVER a facility problem reported in the media can undo that goodwill just as quickly — so the overall effect during the event depends heavily on how smoothly things run.\"</li>\n</ul>\n<p>In <strong>Section B</strong>, use a detail FROM the scenario you are given — a named area, a named problem — not a general example that ignores it.</p>", "question": "What turns a list of positives into a higher-band Discuss answer?", "options": ["Weighing a positive against a negative and reaching a judgement", "Naming as many different positives as possible in the time you have available", "Repeating the exact same point using slightly different words", "Leaving out any mention of negatives completely"]}'::jsonb, '{"answer": 0, "explain": "Higher bands reward balance and a judgement, not volume — a longer list of only positives still caps in the lower bands."}'::jsonb),
('sport-studies:3-3-1-during-the-event:tips:282419a1', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> during-event effects appear as quick recall in <strong>Section A</strong> (identify/state a positive or negative), as applied points in <strong>Section B</strong> scenarios about a named host area, and feed <strong>Section C</strong> 8-mark answers discussing how successful hosting an event has been.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the positives and negatives in themes (community/pride, facilities/tourism/jobs, media, safety) so you can always recall several.</li>\n<li>Remember the same event can produce a positive AND a negative at the same time — that overlap is a strong evaluation point.</li>\n<li>Keep the three stages (before/during/after) straight — an effect from the wrong stage earns nothing, however accurate it is.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One positive during the event is… because…\"</li>\n<li>\"This matters because…\"</li>\n<li>\"On the other hand, a negative effect is… because…\"</li>\n</ul>", "question": "Why is it useful to notice that the same event can produce a positive AND a negative at once?", "options": ["It gives you a strong point for a balanced, higher-band Discuss answer", "It means the whole event has definitely failed and cannot be defended by anyone", "It proves that user groups and during-event effects are the same idea", "It replaces the need to name any effects at all in your answer"]}'::jsonb, '{"answer": 0, "explain": "Showing that one event produces both at once is exactly the kind of balanced, applied point that lifts a Section C answer into a higher band."}'::jsonb),
('sport-studies:3-3-1-during-the-event:fib:05ad86d8', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'fib', 'fib', 1, '{"question": "Venues and transport built for the event now being used is called social _____ in use.", "blankOptions": {"B1": ["short-term", "direct", "pride", "infrastructure"]}}'::jsonb, '{"blanks": {"B1": "infrastructure"}}'::jsonb),
('sport-studies:3-3-1-during-the-event:fib:01e3b889', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'fib', 'fib', 1, '{"question": "A shared sense of national pride and unity while the event is on is called national morale and social _____.", "blankOptions": {"B1": ["direct", "cohesion", "neglected", "pride"]}}'::jsonb, '{"blanks": {"B1": "cohesion"}}'::jsonb),
('sport-studies:3-3-1-during-the-event:fib:d571fc5f', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'fib', 'fib', 1, '{"question": "Temporary jobs created only to cover the event period, such as stewarding, are called _____ employment.", "blankOptions": {"B1": ["short-term", "infrastructure", "pride", "neglected"]}}'::jsonb, '{"blanks": {"B1": "short-term"}}'::jsonb),
('sport-studies:3-3-1-during-the-event:fib:6292548a', 'sport-studies', 'sport-studies:3-3-1-during-the-event', '3.3.1 During the Event', 'fib', 'fib', 1, '{"question": "Spending tied straight to the event itself, like tickets and nearby hotels, is called _____ tourism.", "blankOptions": {"B1": ["direct", "cohesion", "infrastructure", "short-term"]}}'::jsonb, '{"blanks": {"B1": "direct"}}'::jsonb)
